"use strict";(globalThis.webpackChunktjm_solutions_site=globalThis.webpackChunktjm_solutions_site||[]).push([[6944],{1433(e){e.exports=JSON.parse('{"permalink":"/articles/2021/07/07/agility-and-the-headless-commerce-debate","source":"@site/blog/2021-07-07-agility-and-the-headless-commerce-debate.mdx","title":"Agility and the Headless Commerce Debate","description":"Making a headless commerce decision for the whole business, not just the engineering team.","date":"2021-07-07T00:00:00.000Z","tags":[{"inline":true,"label":"digital-commerce","permalink":"/articles/tags/digital-commerce"},{"inline":true,"label":"strategy","permalink":"/articles/tags/strategy"},{"inline":true,"label":"architecture","permalink":"/articles/tags/architecture"}],"readingTime":6.6,"hasTruncateMarker":true,"authors":[{"name":"Tony Moores","title":"Founder & Principal Consultant, TJM Solutions","url":"https://www.tjm.solutions/about","socials":{"linkedin":"https://www.linkedin.com/in/tony-moores/"},"imageURL":"/img/tjm-solutions-logo.png","key":"tony","page":null}],"frontMatter":{"title":"Agility and the Headless Commerce Debate","description":"Making a headless commerce decision for the whole business, not just the engineering team.","date":"2021-07-07T00:00:00.000Z","authors":["tony"],"tags":["digital-commerce","strategy","architecture"],"image":"/img/agility-headless.jpg"},"unlisted":false,"prevItem":{"title":"Headless Commerce: Advice for Goal Hangers","permalink":"/articles/2022/12/16/headless-commerce-advice-for-goal-hangers"},"nextItem":{"title":"Why Do They Call Them Apartments When They\'re All Stuck Together?","permalink":"/articles/2021/03/14/why-do-they-call-them-apartments"}}')},2521(e,t,i){i.r(t),i.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>c,frontMatter:()=>n,metadata:()=>o,toc:()=>d});var o=i(1433),s=i(4848),a=i(8453);const n={title:"Agility and the Headless Commerce Debate",description:"Making a headless commerce decision for the whole business, not just the engineering team.",date:new Date("2021-07-07T00:00:00.000Z"),authors:["tony"],tags:["digital-commerce","strategy","architecture"],image:"/img/agility-headless.jpg"},r=void 0,l={authorsImageUrls:[void 0]},d=[{value:"For Providers, Agility is All About Delivery",id:"for-providers-agility-is-all-about-delivery",level:2},{value:"For Consumers, Agility is All About Operations",id:"for-consumers-agility-is-all-about-operations",level:2},{value:"For Users, Agility is About Gratification",id:"for-users-agility-is-about-gratification",level:2},{value:"Last Thoughts",id:"last-thoughts",level:2}];function h(e){const t={h2:"h2",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components},{Head:i}=t;return i||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Head",!0),(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)(i,{children:[(0,s.jsx)("link",{rel:"canonical",href:"https://tmoores.medium.com/agility-and-the-headless-commerce-debate-making-a-decision-for-the-whole-business-253ead850070"}),(0,s.jsx)("meta",{property:"og:type",content:"article"}),(0,s.jsx)("meta",{property:"article:published_time",content:"2021-07-07T00:00:00Z"}),(0,s.jsx)("meta",{property:"article:author",content:"Tony Moores"}),(0,s.jsx)("script",{type:"application/ld+json",children:'{"@context":"https://schema.org","@type":"BlogPosting","headline":"Agility and the Headless Commerce Debate","description":"Making a headless commerce decision for the whole business, not just the engineering team.","datePublished":"2021-07-07","author":{"@type":"Person","name":"Tony Moores","url":"https://www.tjm.solutions/about"},"publisher":{"@type":"Organization","name":"TJM Solutions","url":"https://www.tjm.solutions"},"url":"https://www.tjm.solutions/articles/2021/07/07/agility-and-the-headless-commerce-debate","mainEntityOfPage":{"@type":"WebPage","@id":"https://www.tjm.solutions/articles/2021/07/07/agility-and-the-headless-commerce-debate"}}'})]}),"\n",(0,s.jsx)(t.p,{children:"So, you are considering headless commerce and have made your way through the talks, videos, and articles but still have not decided what to do? The arguments for transitioning to headless commerce are numerous and touch several domains. It is useful to categorize the value proposition by the segments they impact:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Providers"})," \u2014 Those whose business is the building, delivery, and/or maintenance of digital commerce platforms."]}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Consumers"})," \u2014 Those who subscribe to commerce platforms and/or services as a vehicle to grow their core business."]}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Users"})," \u2014 Those who are immersed in a digital commerce experience."]}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"The return on investment in headless commerce is different for each group. As agility is perhaps the most often cited benefit of headless commerce, let's use that as an example."}),"\n",(0,s.jsx)(t.h2,{id:"for-providers-agility-is-all-about-delivery",children:"For Providers, Agility is All About Delivery"}),"\n",(0,s.jsx)(t.p,{children:"For providers, agility is measured by how quickly they can deliver something new. It's essential for keeping pace with competitive demands and meeting the market where it's going. There is no question that a headless strategy will support agility for digital commerce providers. They can develop features in parallel and deliver them to market faster API-first."}),"\n",(0,s.jsx)(t.p,{children:"Providers who do include a \"head\" must be able to release UI updates independently of their back end. This allows two separate streams of work and the opportunity to tune the processes that drive design, develop, test, and release as frequently as possible. Need more agility? Keep dividing work-streams until the required coordination between work-streams threatens their independence. Indeed, you've heard this argument made for microservice adoption and it's a good one, if you are in the business of building and maintaining core backend services. If your organization has an agile delivery program you brag about at conferences but opted out of headless commerce, you should be writing an article about that. On the other hand, if your delivery organization is riding a barrel over a waterfall and you think going headless will make you agile \u2014 it's time to get a second barrel!"}),"\n",(0,s.jsx)(t.p,{children:"Provider agility is important to their customers too, but digital commerce consumers need to be agile in the consumption of those new features. This may be easier for an organization with a large mature front-end development team to support than one which farms out its design and IT. The latter may be able to adopt new features with greater agility by leveraging a well-tooled front-end framework."}),"\n",(0,s.jsx)(t.h2,{id:"for-consumers-agility-is-all-about-operations",children:"For Consumers, Agility is All About Operations"}),"\n",(0,s.jsx)(t.p,{children:"Alas, adopting emerging vendor features is but a small part of consumer agility. I'm reminded of a John Deere ad: \"It's not how fast you mow, it's how well you mow fast!\" For digital commerce consumers, agility should be measured by how quickly one can make a positive impact. A headless strategy may have both positive and negative impacts on various aspects of running one's business, depending on how it's supported, organized, and staffed. Aside from adopting new provider features, those running digital commerce touchpoints should consider agility in areas like managing assortments, pricing, marketing, analytics, and other high-frequency tasks. Coordinating changes in these areas is typically easier when tooling is present and unified, so a headless strategy that includes independent services from disparate systems should also include support for frequent business operations. Undoubtedly, organizations with highly customized administrative processes will gain agility by building bespoke tools that operate across multiple headless systems if vendor tooling is unavailable or ill-suited. Most will save some time and effort by using the tools at hand, augmenting the gap with custom tools and dashboards over time."}),"\n",(0,s.jsx)(t.p,{children:"Less frequent, yet no less important to consider, are: spinning up a new brand or microsite, the adoption of new payment and fulfillment models, expansion into new channels and markets, integrating value-added services, and developing experiences for new touchpoints and devices. Digital commerce consumers who have successfully adopted agile delivery of their user experiences will surely be able to smoothly leverage the headless commerce value proposition when it's time to address such concerns. However, that does not mean those who haven't will be denied the opportunity to innovate. Microtransactions on smart devices, frictionless returns, and last-mile delivery are not the protected domain of headless practitioners. One might argue that a business's agility in developing sound operational and go-to-market strategies for innovative adoption is more important than how fast they execute. Consider how often these things are done, how much impact they have on the business and its consumers, and what kind of agility is required across the whole program \u2014 rather than just development."}),"\n",(0,s.jsx)(t.h2,{id:"for-users-agility-is-about-gratification",children:"For Users, Agility is About Gratification"}),"\n",(0,s.jsx)(t.p,{children:"We want what we want when and where we want it. Most of us do not want to endure an elaborate product configuration just to find a store we can visit to see it, and most of us would rather not walk through a maze of products we're not interested in to get there. We expect our privacy to be protected but assume call centers and points-of-sale know all about whatever we are doing \u2014 whether on our phone, bike, wearable, or the outdated PC in the hotel lobby. We have goals and we expect an experience that supports their pursuit on whichever head we're facing at the time."}),"\n",(0,s.jsx)(t.p,{children:'What does that have to do with headless commerce? Well, insomuch as you are doing what you need to well, not much at all. There are many articles about the benefits of "going headless," and some make note of end-user benefits \u2014 but those are rather tenuous. Those arguments may be made to the extent that the ability to successfully deliver a great user interface (upon which a great digital experience relies) depends on one\'s headless strategy. However, it remains extremely challenging to relate, much less quantify, the impact of "going headless" \u2014 or any other architectural strategy \u2014 on metrics like traffic, stickiness, average order value, and conversion rates.'}),"\n",(0,s.jsx)(t.h2,{id:"last-thoughts",children:"Last Thoughts"}),"\n",(0,s.jsx)(t.p,{children:"So, you are considering headless commerce, having read one more opinionated article but still have not decided what to do? The very first thing you need to do is understand who you are and what you are trying to do. I submit: if you are a provider, you must support it; if you are an end-user, you probably don't care; if you are already doing it, you should be exploring how to do it with greater agility. But if you're not, my advice is \u2014 don't ignore it. The shoulders of headless commerce: continuous design, development, integration, and delivery of well-orchestrated services, are worth exploring and can boost your agility regardless of where you land on the headless debate."}),"\n",(0,s.jsx)(t.p,{children:"When considering your roadmap, and where to spend your development dollars, ask:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:'What will "move the needle" and help me grow my business?'}),"\n",(0,s.jsx)(t.li,{children:"What is preventing me from doing these things with greater agility?"}),"\n",(0,s.jsx)(t.li,{children:"How will I evaluate the cost to the business against the gain?"}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Remember, great products, great marketing, and great experiences remain the most impactful drivers of the metrics that count the most. Fix what's broken there first and you'll likely find the headless commerce debate sorts itself out on the way."})]})}function c(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(h,{...e})}):h(e)}},8453(e,t,i){i.d(t,{R:()=>n,x:()=>r});var o=i(6540);const s={},a=o.createContext(s);function n(e){const t=o.useContext(a);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:n(e.components),o.createElement(a.Provider,{value:t},e.children)}}}]);